#include<bits/stdc++.h>
using namespace std;
const int N = 1e6;
long long path[10010];
long long vis[10100];
struct stu{
    long long x,y;
}a[10010];
long long n,mx,minn = INT_MAX;
void dfs(long long u){
    if(u > n){
        long long j = 1;
        for(long long i = 1; i <= n; i++){
            j *= a[path[i-1]].x;
            mx = max(mx,j/a[path[i]].y);
        }
        minn = min(minn,mx);
        return;
    }
    for(long long i = 1; i <= n; i++){
        if(vis[i] == 0){
            path[u] = i;
            vis[i] = 1;
            dfs(u + 1);
            vis[i] = 0;
        }
    }
}
int main (){
    cin >> n;
    for(long long i = 0; i <= n; i ++){
        cin >> a[i].x >> a[i].y;
    }
    dfs(1);
    cout <<minn;
    return 0;
}
